import React, { useEffect } from 'react';

export default function AlertPopup({ alert, onClose }) {
  useEffect(() => {
    const t = setTimeout(onClose, 9000);
    return () => clearTimeout(t);
  }, [onClose]);

  const isCritical = alert.risk_level === 'critical';
  const isHigh = alert.risk_level === 'high';

  return (
    <div className="animate-slide-in-right" style={{
      width: '340px',
      background: 'var(--bg-panel)',
      border: `1px solid ${isCritical ? 'rgba(255,51,102,0.5)' : isHigh ? 'rgba(255,102,0,0.5)' : 'rgba(255,170,0,0.4)'}`,
      boxShadow: isCritical ? 'var(--glow-red)' : isHigh ? '0 0 20px rgba(255,102,0,0.3)' : '0 0 20px rgba(255,170,0,0.2)',
      position: 'relative', overflow: 'hidden',
    }}>
      {/* Top bar */}
      <div style={{
        height: '3px',
        background: isCritical ? 'var(--accent-red)' : isHigh ? '#ff6600' : 'var(--accent-amber)',
        animation: 'pulse-glow 1s infinite',
      }} />

      <div style={{ padding: '14px 16px' }}>
        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '10px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{
              fontFamily: "'Space Mono', monospace", fontSize: '8px', letterSpacing: '0.15em',
              color: isCritical ? 'var(--accent-red)' : isHigh ? '#ff6600' : 'var(--accent-amber)',
              background: isCritical ? 'rgba(255,51,102,0.1)' : 'rgba(255,170,0,0.1)',
              padding: '3px 8px', border: `1px solid ${isCritical ? 'rgba(255,51,102,0.3)' : 'rgba(255,170,0,0.3)'}`,
            }}>
              ⚠ {(alert.risk_level || 'MEDIUM').toUpperCase()} THREAT
            </span>
          </div>
          <button onClick={onClose} style={{ background: 'none', border: 'none', color: 'var(--text-dim)', cursor: 'pointer', fontSize: '12px', padding: '0 4px' }}>✕</button>
        </div>

        {/* Device name */}
        <div style={{ fontWeight: '700', fontSize: '15px', color: 'var(--text-primary)', marginBottom: '8px', letterSpacing: '0.02em' }}>
          {alert.device_name || 'Unknown USB Device'}
        </div>

        {/* Details */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '3px' }}>
          {[
            { k: 'HOST', v: alert.hostname },
            { k: 'VID',  v: alert.vendor_id },
            { k: 'PID',  v: alert.product_id },
          ].filter(x => x.v && x.v !== 'unknown').map(({ k, v }) => (
            <div key={k} style={{ display: 'flex', gap: '8px', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>
              <span style={{ color: 'var(--text-dim)', minWidth: '30px' }}>{k}</span>
              <span style={{ color: 'var(--accent-cyan)' }}>{v}</span>
            </div>
          ))}
          <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-muted)', marginTop: '4px' }}>
            {new Date().toLocaleTimeString()}
          </div>
        </div>
      </div>

      {/* Progress bar (auto-close timer) */}
      <div style={{
        height: '2px', background: 'var(--border-dim)',
        position: 'absolute', bottom: 0, left: 0, right: 0,
      }}>
        <div style={{
          height: '100%', background: isCritical ? 'var(--accent-red)' : 'var(--accent-amber)',
          animation: 'shrink 9s linear forwards',
          transformOrigin: 'left',
        }} />
      </div>

      <style>{`@keyframes shrink { from { width: 100%; } to { width: 0%; } }`}</style>
    </div>
  );
}
